/**
 * Letters Theme — Client-side Search
 *
 * Fetches /api/search.json (generated by Gridea Pro at build time) on first
 * open, then performs real-time fuzzy search with CJK awareness, keyboard
 * navigation, highlighted excerpts, and full accessibility support.
 *
 * Pure vanilla JS, no dependencies.
 */

(function () {
  "use strict";

  /* ---------- Constants ---------- */
  var SEARCH_JSON_URL = '/api/search.json';
  var MAX_RESULTS = 20;
  var DEBOUNCE_MS = 300;
  var SNIPPET_RADIUS = 60;

  /* ---------- DOM references ---------- */
  var overlay = document.querySelector(".search-overlay");
  var input = document.querySelector(".search-input");
  var resultsContainer = document.querySelector(".search-results");
  var closeButton = document.querySelector(".search-close");

  if (!overlay || !input || !resultsContainer) return;

  /* ---------- State ---------- */
  var debounceTimer = null;
  var posts = null;  // cached JSON — null means "not yet fetched"
  var searchData = [];
  var isLoading = false;
  var isOpen = false;

  /* ---------- Data fetching (lazy-load once, cache in memory) ---------- */
  function ensureData(callback) {
    if (posts !== null) return callback();
    if (isLoading) return;
    isLoading = true;

    var xhr = new XMLHttpRequest();
    xhr.open('GET', SEARCH_JSON_URL, true);
    xhr.onreadystatechange = function () {
      if (xhr.readyState !== 4) return;
      isLoading = false;
      try {
        posts = xhr.status === 200 ? JSON.parse(xhr.responseText) : [];
      } catch (_) {
        posts = [];
      }
      // Map search.json fields to internal format
      searchData = posts.map(function (item) {
        return {
          title: item.title || "",
          url: item.link || "",
          content: item.content || "",
          tags: Array.isArray(item.tags) ? item.tags : [],
          date: item.date || "",
          _title: (item.title || "").toLowerCase(),
          _content: (item.content || "").toLowerCase(),
          _tags: (Array.isArray(item.tags) ? item.tags : [])
            .join(" ")
            .toLowerCase(),
        };
      });
      callback();
    };
    xhr.send();
  }

  /* ---------- Open / Close ---------- */
  function open() {
    if (isOpen) return;
    isOpen = true;
    overlay.classList.add("open");
    overlay.style.display = "";
    document.body.style.overflow = "hidden";
    requestAnimationFrame(function () {
      input.focus();
    });
  }

  function close() {
    if (!isOpen) return;
    isOpen = false;
    overlay.classList.remove("open");
    overlay.style.display = "none";
    document.body.style.overflow = "";
    input.value = "";
    resultsContainer.innerHTML = "";
  }

  /* ---------- Expose openSearch globally for header button ---------- */
  window.openSearch = function () {
    ensureData(open);
  };

  /* ---------- Fuzzy search ---------- */
  function search(query) {
    if (!query || query.trim().length === 0) {
      resultsContainer.innerHTML = "";
      return;
    }

    var terms = query
      .toLowerCase()
      .split(/\s+/)
      .filter(function (t) {
        return t.length > 0;
      });

    if (terms.length === 0) {
      resultsContainer.innerHTML = "";
      return;
    }

    var scored = [];
    for (var i = 0; i < searchData.length; i++) {
      var item = searchData[i];
      var score = 0;

      for (var j = 0; j < terms.length; j++) {
        var term = terms[j];
        if (item._title.indexOf(term) !== -1) {
          score += 10;
        }
        if (item._tags.indexOf(term) !== -1) {
          score += 5;
        }
        if (item._content.indexOf(term) !== -1) {
          score += 1;
        }
      }

      if (score > 0) {
        scored.push({ item: item, score: score });
      }
    }

    scored.sort(function (a, b) {
      if (b.score !== a.score) return b.score - a.score;
      return b.item.date > a.item.date ? 1 : -1;
    });

    var results = scored.slice(0, MAX_RESULTS);
    renderResults(results, terms);
  }

  /* ---------- Highlight helper ---------- */
  function escapeHTML(str) {
    return str
      .replace(/&/g, "&amp;")
      .replace(/</g, "&lt;")
      .replace(/>/g, "&gt;")
      .replace(/"/g, "&quot;");
  }

  function escapeRegExp(str) {
    return str.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
  }

  function highlightTerms(text, terms) {
    var escaped = escapeHTML(text);
    for (var i = 0; i < terms.length; i++) {
      var safeterm = escapeHTML(escapeRegExp(terms[i]));
      var re = new RegExp("(" + safeterm + ")", "gi");
      escaped = escaped.replace(re, "<mark>$1</mark>");
    }
    return escaped;
  }

  function buildSnippet(content, terms) {
    var lower = content.toLowerCase();
    var firstIndex = -1;

    for (var i = 0; i < terms.length; i++) {
      var idx = lower.indexOf(terms[i]);
      if (idx !== -1 && (firstIndex === -1 || idx < firstIndex)) {
        firstIndex = idx;
      }
    }

    if (firstIndex === -1) {
      return content.substring(0, SNIPPET_RADIUS * 2);
    }

    var start = Math.max(0, firstIndex - SNIPPET_RADIUS);
    var end = Math.min(content.length, firstIndex + SNIPPET_RADIUS);
    var snippet = "";
    if (start > 0) snippet += "...";
    snippet += content.substring(start, end);
    if (end < content.length) snippet += "...";
    return snippet;
  }

  /* ---------- Render ---------- */
  function renderResults(results, terms) {
    if (results.length === 0) {
      resultsContainer.innerHTML =
        '<div class="search-empty">' +
        '<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor">' +
        '<path stroke-linecap="round" stroke-linejoin="round" d="M21 21l-5.197-5.197m0 0A7.5 7.5 0 105.196 5.196a7.5 7.5 0 0010.607 10.607z"/>' +
        "</svg>" +
        "<p>No results found</p>" +
        "</div>";
      return;
    }

    var html = "";
    for (var i = 0; i < results.length; i++) {
      var r = results[i].item;
      var snippet = buildSnippet(r.content, terms);

      html +=
        '<a class="search-result-item" href="' +
        escapeHTML(r.url) +
        '">' +
        '<div class="search-result-title">' +
        highlightTerms(r.title, terms) +
        "</div>" +
        '<div class="search-result-snippet">' +
        highlightTerms(snippet, terms) +
        "</div>" +
        (r.date
          ? '<div class="search-result-date">' + escapeHTML(r.date) + "</div>"
          : "") +
        "</a>";
    }

    resultsContainer.innerHTML = html;
  }

  /* ---------- Debounced input handler ---------- */
  function onInput() {
    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(function () {
      search(input.value);
    }, DEBOUNCE_MS);
  }

  /* ---------- Event listeners ---------- */
  // Close button
  if (closeButton) {
    closeButton.addEventListener("click", close);
  }

  // Click on overlay background closes modal
  overlay.addEventListener("click", function (e) {
    if (e.target === overlay) {
      close();
    }
  });

  // Keyboard shortcuts
  document.addEventListener("keydown", function (e) {
    if ((e.ctrlKey || e.metaKey) && e.key === "k") {
      e.preventDefault();
      if (isOpen) {
        close();
      } else {
        ensureData(open);
      }
      return;
    }

    if (e.key === "Escape" && isOpen) {
      e.preventDefault();
      close();
    }
  });

  // Input
  input.addEventListener("input", onInput);

  // Enter navigates to first result
  input.addEventListener("keydown", function (e) {
    if (e.key === "Enter") {
      e.preventDefault();
      var firstResult = resultsContainer.querySelector(".search-result-item");
      if (firstResult) {
        window.location.href = firstResult.getAttribute("href");
      }
    }
  });
})();
